import React, { useState, useEffect, useRef } from 'react';
import { supabase } from '../lib/supabaseClient';
import { Student, JobPosting, JobApplication, JobMessage } from '../types';
import { Search, MapPin, DollarSign, Briefcase, Sparkles, Send, ChevronRight, Clock, CheckCircle, Loader2, MessageSquare, ArrowLeft, XCircle, Bell, User } from 'lucide-react';

interface JobBoardProps {
  user: Student;
}

const JobBoard: React.FC<JobBoardProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'all' | 'for-you' | 'applications'>('all');
  const [jobs, setJobs] = useState<JobPosting[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Application State
  const [applyingId, setApplyingId] = useState<string | null>(null);

  // Chat State
  const [activeChatApplication, setActiveChatApplication] = useState<JobApplication | null>(null);
  const [messages, setMessages] = useState<JobMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchJobs();
    if (user.id) fetchApplications();
  }, [user.id]);

  useEffect(() => {
    let interval: any;
    if (activeChatApplication) {
      fetchMessages(activeChatApplication.id);
      // Poll for new messages every 3 seconds
      interval = setInterval(() => fetchMessages(activeChatApplication.id!), 3000); 
    }
    return () => clearInterval(interval);
  }, [activeChatApplication]);

  // Scroll to bottom of chat when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeChatApplication]);

  // Auto-hide toast
  useEffect(() => {
    if (toast) {
        const timer = setTimeout(() => setToast(null), 3000);
        return () => clearTimeout(timer);
    }
  }, [toast]);

  const showToast = (message: string, type: 'success' | 'error') => {
      setToast({ message, type });
  };

  const fetchJobs = async () => {
    setLoading(true);
    const { data } = await supabase
      .from('job_postings')
      .select('*')
      .eq('is_active', true)
      .order('created_at', { ascending: false });

    if (data) setJobs(data);
    setLoading(false);
  };

  const fetchApplications = async () => {
    if (!user.id) return;

    // Check both columns to be safe
    const { data, error } = await supabase
      .from('job_applications')
      .select('*, job_posting:job_postings(*)')
      .or(`student_id.eq.${user.id},alumni_id.eq.${user.id}`)
      .order('applied_at', { ascending: false });

    if (error) console.error("Error fetching applications:", error);
    if (data) setApplications(data);
  };

  const fetchMessages = async (appId: string) => {
    const { data } = await supabase
      .from('job_messages')
      .select('*')
      .eq('application_id', appId)
      .order('sent_at', { ascending: true });

    if (data) setMessages(data);
  };

  const applyForJob = async (jobId: string) => {
    if (!user.id) {
        showToast("Error: User session invalid. Please log in again.", 'error');
        return;
    }

    if(!window.confirm("Are you sure you want to apply for this position?")) return;

    setApplyingId(jobId);

    try {
        const payload: any = {
          job_posting_id: jobId,
          application_status: 'Pending'
        };

        // Strict Logic to determine which ID column to use
        // This relies on the fact that an applicant is EITHER in the students table OR alumni table
        const isStudentTable = user.table_source === 'students' || user.enrollment_status === 'Graduating';

        if (isStudentTable) {
            payload.student_id = user.id;
            payload.alumni_id = null;
        } else {
            payload.alumni_id = user.id;
            payload.student_id = null;
        }

        const { error } = await supabase.from('job_applications').insert([payload]);

        if (error) {
          console.error("Apply Error:", error);
          if (error.code === '23505') { // Unique violation
              showToast("You have already applied for this job.", 'error');
          } else {
              showToast("Failed to apply. Please try again.", 'error');
          }
        } else {
          await fetchApplications();
          showToast("Application submitted successfully!", 'success');
          setActiveTab('applications'); 
        }
    } catch (err) {
        console.error("Unexpected error:", err);
        showToast("An unexpected error occurred.", 'error');
    } finally {
        setApplyingId(null);
    }
  };

  const sendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!activeChatApplication || !newMessage.trim()) return;

    // Determine sender type based on who the application belongs to
    const isStudentApplicant = !!activeChatApplication.student_id;

    const payload: any = {
      application_id: activeChatApplication.id,
      sender_type: isStudentApplicant ? 'STUDENT' : 'ALUMNI',
      message: newMessage,
    };

    if (isStudentApplicant) payload.student_id = user.id;
    else payload.alumni_id = user.id;

    const { error } = await supabase.from('job_messages').insert([payload]);

    if (error) {
        console.error("Send Message Error:", error);
        showToast("Failed to send message.", 'error');
    } else {
        setNewMessage('');
        fetchMessages(activeChatApplication.id);
    }
  };

  // Filter Logic
  const filteredJobs = jobs.filter(job => {
    const matchesSearch = job.job_title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          job.company_name.toLowerCase().includes(searchTerm.toLowerCase());

    if (activeTab === 'for-you') {
      const programKeywords = user.program ? user.program.split(' ').filter(w => w.length > 3) : [];
      const matchesProgram = programKeywords.some(keyword => 
         job.job_title.toLowerCase().includes(keyword.toLowerCase()) || 
         job.job_description.toLowerCase().includes(keyword.toLowerCase())
      );
      return matchesSearch && matchesProgram;
    }

    return matchesSearch;
  });

  const hasApplied = (jobId: string) => {
    return applications.some(app => app.job_posting_id === jobId);
  };

  // --- Render Chat Interface ---
  if (activeChatApplication) {
    return (
      <div className="bg-white rounded-3xl shadow-xl border border-gray-200 overflow-hidden h-[650px] flex flex-col animate-slide-up relative">
         {/* Chat Header */}
         <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white z-10 shadow-sm">
            <div className="flex items-center gap-4">
               <button 
                 onClick={() => setActiveChatApplication(null)} 
                 className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500 hover:text-violet-600"
               >
                   <ArrowLeft size={20}/>
               </button>
               <div>
                 <h3 className="font-bold text-gray-800 text-lg leading-tight">{activeChatApplication.job_posting?.company_name}</h3>
                 <p className="text-xs text-gray-500 font-medium">Position: {activeChatApplication.job_posting?.job_title}</p>
               </div>
            </div>
            <div className="flex flex-col items-end">
                <span className="text-[10px] uppercase font-bold text-gray-400">Application Status</span>
                <span className={`text-xs font-bold px-2 py-1 rounded-full border ${
                   activeChatApplication.application_status === 'Hired' ? 'bg-green-100 text-green-700 border-green-200' :
                   activeChatApplication.application_status === 'Rejected' ? 'bg-red-50 text-red-600 border-red-100' :
                   'bg-blue-50 text-blue-600 border-blue-100'
                }`}>
                   {activeChatApplication.application_status}
                </span>
            </div>
         </div>

         {/* Messages Area */}
         <div className="flex-grow p-6 overflow-y-auto space-y-6 bg-gray-50/50" style={{ backgroundImage: 'radial-gradient(#e5e7eb 1px, transparent 1px)', backgroundSize: '20px 20px' }}>
            {messages.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-gray-400 space-y-3">
                    <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm">
                        <MessageSquare size={32} className="text-violet-300"/>
                    </div>
                    <p className="text-sm font-medium">Start the conversation with the hiring manager.</p>
                </div>
            ) : (
                messages.map(msg => {
                    const isMe = msg.sender_type === 'ALUMNI' || msg.sender_type === 'STUDENT';
                    return (
                        <div key={msg.id} className={`flex w-full ${isMe ? 'justify-end' : 'justify-start'}`}>
                             <div className={`flex flex-col ${isMe ? 'items-end' : 'items-start'} max-w-[75%]`}>
                                 <div className={`px-5 py-3 rounded-2xl text-sm shadow-sm relative ${
                                     isMe 
                                     ? 'bg-violet-600 text-white rounded-br-none' 
                                     : 'bg-white border border-gray-200 text-gray-700 rounded-bl-none'
                                 }`}>
                                     {msg.message}
                                 </div>
                                 <span className="text-[10px] text-gray-400 mt-1 px-1 flex items-center gap-1">
                                     {!isMe && <User size={10} />}
                                     {new Date(msg.sent_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                 </span>
                             </div>
                        </div>
                    )
                })
            )}
            <div ref={messagesEndRef} />
         </div>

         {/* Input Area */}
         <form onSubmit={sendMessage} className="p-4 bg-white border-t border-gray-100 flex gap-3 items-center">
            <input 
              type="text" 
              value={newMessage} 
              onChange={e => setNewMessage(e.target.value)}
              placeholder="Type your message here..."
              className="flex-grow px-5 py-3.5 bg-gray-50 rounded-2xl border-none focus:ring-2 focus:ring-violet-100 focus:bg-white transition-all outline-none text-sm font-medium text-gray-700 placeholder-gray-400"
            />
            <button 
                type="submit" 
                disabled={!newMessage.trim()}
                className="p-3.5 bg-violet-600 text-white rounded-2xl hover:bg-violet-700 transition-all shadow-lg shadow-violet-200 disabled:opacity-50 disabled:shadow-none hover:scale-105 active:scale-95"
            >
                <Send size={20} />
            </button>
         </form>
      </div>
    )
  }

  // --- Main Job Board Render ---
  return (
    <div className="space-y-6 animate-slide-up relative">
        {/* Toast Notification */}
        {toast && (
            <div className={`fixed top-24 right-6 z-50 px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-5 fade-in duration-300 ${toast.type === 'success' ? 'bg-white border-l-4 border-green-500 text-green-800' : 'bg-white border-l-4 border-red-500 text-red-800'}`}>
                {toast.type === 'success' ? <CheckCircle size={20}/> : <XCircle size={20}/>}
                <span className="font-bold text-sm">{toast.message}</span>
            </div>
        )}

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-end gap-4 bg-gradient-to-r from-violet-600 to-indigo-600 p-8 rounded-3xl text-white shadow-xl shadow-violet-200">
             <div>
                <h2 className="text-3xl font-bold mb-2 font-display">Find Your Next Career</h2>
                <p className="opacity-90 font-medium">Discover opportunities tailored for Laguna University graduates.</p>
             </div>
             <div className="relative w-full md:w-80">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Search jobs or companies..." 
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 rounded-xl text-gray-800 focus:outline-none shadow-lg shadow-black/10 border-0 placeholder-gray-400"
                />
             </div>
        </div>

        {/* Tabs */}
        <div className="flex gap-1 border-b border-gray-200 px-2 overflow-x-auto">
            <button 
               onClick={() => setActiveTab('all')}
               className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all whitespace-nowrap ${activeTab === 'all' ? 'border-violet-600 text-violet-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
               All Jobs
            </button>
            <button 
               onClick={() => setActiveTab('for-you')}
               className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'for-you' ? 'border-violet-600 text-violet-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
               <Sparkles size={16} className={activeTab === 'for-you' ? 'fill-violet-200' : ''} /> For You
            </button>
            <button 
               onClick={() => setActiveTab('applications')}
               className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'applications' ? 'border-violet-600 text-violet-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
               My Applications 
               {applications.length > 0 && (
                   <span className="bg-violet-100 text-violet-700 px-2 py-0.5 rounded-full text-[10px]">{applications.length}</span>
               )}
            </button>
        </div>

        {/* Content */}
        {activeTab === 'applications' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in">
                 {applications.length === 0 ? (
                     <div className="col-span-full flex flex-col items-center justify-center py-20 text-gray-400">
                         <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                            <Briefcase className="opacity-50" size={32}/>
                         </div>
                         <p className="font-bold">You haven't applied to any jobs yet.</p>
                         <button onClick={() => setActiveTab('all')} className="mt-4 text-violet-600 font-bold hover:underline">Browse Jobs</button>
                     </div>
                 ) : (
                     applications.map(app => (
                         <div key={app.id} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col h-full hover:shadow-md transition-all group">
                             <div className="flex justify-between items-start mb-4">
                                 <div>
                                     <h3 className="font-bold text-gray-800 text-lg line-clamp-1" title={app.job_posting?.job_title}>{app.job_posting?.job_title}</h3>
                                     <p className="text-sm text-gray-500 font-medium flex items-center gap-1 mt-1">
                                         <Briefcase size={12}/> {app.job_posting?.company_name}
                                     </p>
                                 </div>
                                 <div className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase border tracking-wide ${
                                     app.application_status === 'Hired' ? 'bg-green-50 text-green-700 border-green-200' :
                                     app.application_status === 'Rejected' ? 'bg-red-50 text-red-700 border-red-200' :
                                     'bg-blue-50 text-blue-700 border-blue-200'
                                 }`}>
                                     {app.application_status}
                                 </div>
                             </div>

                             <div className="flex-grow border-t border-dashed border-gray-100 pt-4 mt-2">
                                 <div className="flex justify-between items-center text-xs text-gray-400 mb-6">
                                     <span>Applied on</span>
                                     <span className="font-bold text-gray-600">{new Date(app.applied_at).toLocaleDateString()}</span>
                                 </div>
                             </div>

                             <button 
                               onClick={() => setActiveChatApplication(app)}
                               className="w-full py-3 bg-violet-50 text-violet-600 rounded-xl text-sm font-bold hover:bg-violet-100 transition-colors flex items-center justify-center gap-2 group-hover:bg-violet-600 group-hover:text-white"
                             >
                                <MessageSquare size={16} /> Messages
                             </button>
                         </div>
                     ))
                 )}
             </div>
        ) : (
             <div className="grid grid-cols-1 gap-4 animate-fade-in">
                 {loading ? (
                     <div className="flex flex-col items-center justify-center py-20">
                         <Loader2 className="animate-spin text-violet-600 mb-2" size={32} />
                         <span className="text-gray-400 font-medium">Loading jobs...</span>
                     </div>
                 ) : filteredJobs.map(job => (
                     <div key={job.id} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all group relative overflow-hidden">
                         {hasApplied(job.id) && (
                             <div className="absolute top-0 right-0 bg-green-500 text-white text-[10px] font-bold px-3 py-1 rounded-bl-xl z-10">
                                 APPLIED
                             </div>
                         )}
                         <div className="flex flex-col md:flex-row justify-between gap-6">
                             <div className="flex-grow">
                                 <div className="flex justify-between items-start">
                                     <div>
                                        <h3 className="text-xl font-bold text-gray-800 group-hover:text-violet-600 transition-colors">{job.job_title}</h3>
                                        <div className="flex items-center gap-2 text-sm font-medium text-gray-500 mt-1">
                                            <Briefcase size={14} className="text-violet-400" /> {job.company_name}
                                        </div>
                                     </div>
                                 </div>

                                 <div className="flex flex-wrap gap-3 my-4">
                                     <span className="px-3 py-1 bg-gray-50 rounded-lg text-xs font-bold text-gray-600 flex items-center gap-1 border border-gray-100">
                                         <MapPin size={12}/> {job.location || 'Remote'}
                                     </span>
                                     <span className="px-3 py-1 bg-gray-50 rounded-lg text-xs font-bold text-gray-600 flex items-center gap-1 border border-gray-100">
                                         <Clock size={12}/> {job.employment_type}
                                     </span>
                                     <span className="px-3 py-1 bg-green-50 rounded-lg text-xs font-bold text-green-700 flex items-center gap-1 border border-green-100">
                                         <DollarSign size={12}/> {job.salary_range || 'Competitive'}
                                     </span>
                                 </div>

                                 <p className="text-sm text-gray-600 line-clamp-2 leading-relaxed max-w-3xl">{job.job_description}</p>
                             </div>

                             <div className="flex flex-col justify-between shrink-0 min-w-[140px] items-end">
                                 <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wide mb-2 bg-gray-50 px-2 py-1 rounded">
                                     {new Date(job.created_at).toLocaleDateString()}
                                 </span>
                                 <button 
                                    onClick={() => applyForJob(job.id)}
                                    disabled={hasApplied(job.id) || applyingId === job.id}
                                    className={`w-full py-3 px-4 rounded-xl text-sm font-bold shadow-sm transition-all flex items-center justify-center gap-2 ${
                                        hasApplied(job.id) 
                                        ? 'bg-gray-100 text-gray-400 cursor-not-allowed border border-gray-200' 
                                        : 'bg-gray-900 text-white hover:bg-violet-600 hover:shadow-violet-200 hover:-translate-y-0.5'
                                    }`}
                                 >
                                     {applyingId === job.id ? (
                                         <Loader2 className="animate-spin" size={16} />
                                     ) : hasApplied(job.id) ? (
                                         <><CheckCircle size={16}/> Applied</>
                                     ) : (
                                         'Apply Now'
                                     )}
                                 </button>
                             </div>
                         </div>
                     </div>
                 ))}
                 {filteredJobs.length === 0 && !loading && (
                     <div className="text-center py-20 text-gray-400">
                         No jobs found matching your criteria.
                     </div>
                 )}
             </div>
        )}
    </div>
  );
};

export default JobBoard;

import React, { useState, useEffect, useRef } from 'react';
import { HR, JobPosting, JobApplication, JobMessage, Student } from '../types';
import { LogOut, Briefcase, Users, MessageSquare, Plus, Search, Trash2, Edit, ChevronRight, Send, X, Eye, CheckCircle, XCircle, FileText, Download } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { sendHiredEmail } from '../services/emailService';
import { parseResume } from '../services/resumeService';

interface HRDashboardProps {
  hr: HR;
  onLogout: () => void;
}

const HRDashboard: React.FC<HRDashboardProps> = ({ hr, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'jobs' | 'applicants' | 'messages'>('jobs');

  // Data State
  const [jobs, setJobs] = useState<JobPosting[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);

  // Job Form State
  const [showJobForm, setShowJobForm] = useState(false);
  const [jobFormData, setJobFormData] = useState<Partial<JobPosting>>({ employment_type: 'Full-Time' });

  // Applicant View State
  const [selectedApplicant, setSelectedApplicant] = useState<JobApplication | null>(null);
  const [showApplicantModal, setShowApplicantModal] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<JobMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Resume Viewing
  const [resumeUrl, setResumeUrl] = useState<string | null>(null);

  useEffect(() => {
    fetchJobs();
  }, []);

  useEffect(() => {
    if (activeTab === 'applicants' || activeTab === 'messages') {
        fetchApplications();
    }
  }, [activeTab]);

  // Polling for messages when chat is active
  useEffect(() => {
    let interval: any;
    if (selectedApplicant) {
        fetchMessages(selectedApplicant.id);
        interval = setInterval(() => fetchMessages(selectedApplicant.id), 3000);
    }
    return () => clearInterval(interval);
  }, [selectedApplicant]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const fetchJobs = async () => {
    const { data } = await supabase.from('job_postings').select('*').eq('hr_id', hr.id).order('created_at', { ascending: false });
    if (data) setJobs(data);
  };

  const fetchApplications = async () => {
    // We need to fetch applications linked to jobs posted by this HR
    // Uses !inner join to filter applications where job_posting.hr_id matches current HR
    const { data, error } = await supabase
        .from('job_applications')
        .select(`
            *,
            job_posting:job_postings!inner(*),
            student:students(*),
            alumni:alumni(*)
        `)
        .eq('job_posting.hr_id', hr.id)
        .order('applied_at', { ascending: false });

    if (error) console.error(error);

    if (data) {
        // Normalize applicant details into one field 'applicant_details'
        // An application will have either 'student' or 'alumni' populated, not both
        const formatted = data.map((app: any) => ({
            ...app,
            applicant_details: app.student || app.alumni
        }));
        setApplications(formatted);
    }
  };

  const fetchMessages = async (appId: string) => {
      const { data } = await supabase
        .from('job_messages')
        .select('*')
        .eq('application_id', appId)
        .order('sent_at', { ascending: true });
      if (data) setMessages(data);
  };

  const handleJobSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = { ...jobFormData, hr_id: hr.id, company_name: hr.company_name };

    if (jobFormData.id) {
        await supabase.from('job_postings').update(payload).eq('id', jobFormData.id);
    } else {
        await supabase.from('job_postings').insert([payload]);
    }
    setShowJobForm(false);
    setJobFormData({ employment_type: 'Full-Time' });
    fetchJobs();
  };

  const deleteJob = async (id: string) => {
      if(!confirm("Are you sure? This will delete all applications associated with this job.")) return;
      await supabase.from('job_postings').delete().eq('id', id);
      fetchJobs();
  };

  const updateApplicationStatus = async (id: string, status: string) => {
      await supabase.from('job_applications').update({ application_status: status }).eq('id', id);

      if (status === 'Hired' && selectedApplicant?.applicant_details?.email) {
          const user = selectedApplicant.applicant_details;
          const instructions = prompt("Enter next steps for the candidate (e.g., Report to office on Monday at 9AM):", "Please wait for our HR to contact you for onboarding.");
          if (instructions) {
              await sendHiredEmail(
                  `${user.first_name} ${user.last_name}`, 
                  user.email, 
                  selectedApplicant.job_posting?.job_title || 'Position',
                  hr.company_name,
                  instructions
              );
              alert("Hired status updated and email sent!");
          }
      }

      fetchApplications();
      if (selectedApplicant) setSelectedApplicant(prev => ({ ...prev!, application_status: status as any }));
  };

  const sendMessage = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedApplicant || !newMessage.trim()) return;

      const payload = {
          application_id: selectedApplicant.id,
          sender_type: 'HR',
          hr_id: hr.id,
          message: newMessage
      };

      const { error } = await supabase.from('job_messages').insert([payload]);

      if (error) {
          console.error("Message send failed:", error);
      } else {
          setNewMessage('');
          fetchMessages(selectedApplicant.id);
      }
  };

  // Helper to View Resume (Convert Hex to Blob)
  const viewResume = (applicant: Student) => {
      if (!applicant.resume) {
          alert("No resume uploaded.");
          return;
      }

      try {
          // Convert hex string to byte array
          const hex = applicant.resume.replace(/^\\x/, '');
          const bytes = new Uint8Array(hex.length / 2);
          for (let i = 0; i < hex.length; i += 2) {
              bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);
          }

          const blob = new Blob([bytes], { type: 'application/pdf' });
          const url = URL.createObjectURL(blob);
          setResumeUrl(url);
      } catch (e) {
          console.error("Error displaying resume:", e);
          alert("Error displaying resume file.");
      }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans text-slate-800">

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
          <div className="container mx-auto px-6 py-4 flex justify-between items-center">
              <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold shadow-md">HR</div>
                  <div>
                      <h1 className="text-xl font-bold text-gray-800 leading-none">HR Portal</h1>
                      <p className="text-xs text-gray-500 font-bold">{hr.company_name}</p>
                  </div>
              </div>
              <button onClick={onLogout} className="flex items-center gap-2 text-gray-500 hover:text-red-500 font-bold text-sm transition-colors">
                  <LogOut size={16} /> Sign Out
              </button>
          </div>
      </header>

      <div className="flex-grow container mx-auto px-6 py-8 grid grid-cols-12 gap-8">

          {/* Sidebar */}
          <div className="col-span-3">
              <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden sticky top-28">
                  <button onClick={() => setActiveTab('jobs')} className={`w-full flex items-center gap-3 px-6 py-4 font-bold text-sm transition-colors ${activeTab === 'jobs' ? 'bg-indigo-50 text-indigo-600 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}>
                      <Briefcase size={18} /> Posted Jobs
                  </button>
                  <button onClick={() => setActiveTab('applicants')} className={`w-full flex items-center gap-3 px-6 py-4 font-bold text-sm transition-colors ${activeTab === 'applicants' ? 'bg-indigo-50 text-indigo-600 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}>
                      <Users size={18} /> Applicants
                  </button>
                  <button onClick={() => setActiveTab('messages')} className={`w-full flex items-center gap-3 px-6 py-4 font-bold text-sm transition-colors ${activeTab === 'messages' ? 'bg-indigo-50 text-indigo-600 border-r-4 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'}`}>
                      <MessageSquare size={18} /> Messages
                  </button>
              </div>
          </div>

          {/* Main Content */}
          <div className="col-span-9 space-y-6">

              {/* JOBS TAB */}
              {activeTab === 'jobs' && (
                  <div className="animate-fade-in">
                      <div className="flex justify-between items-center mb-6">
                          <h2 className="text-2xl font-bold">Your Job Postings</h2>
                          <button onClick={() => { setJobFormData({ employment_type: 'Full-Time' }); setShowJobForm(true); }} className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-sm shadow-md hover:bg-indigo-700 transition-all flex items-center gap-2">
                              <Plus size={18} /> Post New Job
                          </button>
                      </div>

                      <div className="space-y-4">
                          {jobs.map(job => (
                              <div key={job.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm flex justify-between items-start hover:shadow-md transition-shadow">
                                  <div>
                                      <h3 className="text-xl font-bold text-gray-800">{job.job_title}</h3>
                                      <div className="flex gap-3 text-xs font-bold text-gray-500 mt-2 uppercase tracking-wide">
                                          <span className="bg-gray-100 px-2 py-1 rounded">{job.employment_type}</span>
                                          <span className="bg-gray-100 px-2 py-1 rounded">{job.location || 'Remote'}</span>
                                          <span className="bg-gray-100 px-2 py-1 rounded">{job.salary_range || 'Negotiable'}</span>
                                      </div>
                                      <p className="mt-4 text-sm text-gray-600 max-w-2xl line-clamp-2">{job.job_description}</p>
                                  </div>
                                  <div className="flex gap-2">
                                      <button onClick={() => { setJobFormData(job); setShowJobForm(true); }} className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"><Edit size={18}/></button>
                                      <button onClick={() => deleteJob(job.id)} className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={18}/></button>
                                  </div>
                              </div>
                          ))}
                          {jobs.length === 0 && (
                              <div className="text-center py-20 text-gray-400 bg-white rounded-2xl border border-dashed border-gray-200">
                                  No jobs posted yet.
                              </div>
                          )}
                      </div>
                  </div>
              )}

              {/* APPLICANTS & MESSAGES TAB (Simplified to utilize same modal logic) */}
              {(activeTab === 'applicants' || activeTab === 'messages') && (
                  <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden animate-fade-in flex h-[600px]">

                      {/* List */}
                      <div className="w-1/3 border-r border-gray-100 overflow-y-auto">
                          {applications.map(app => (
                              <div 
                                key={app.id} 
                                onClick={() => { setSelectedApplicant(app); setShowApplicantModal(true); }}
                                className={`p-4 border-b border-gray-50 cursor-pointer hover:bg-gray-50 transition-colors ${selectedApplicant?.id === app.id ? 'bg-indigo-50' : ''}`}
                              >
                                  <div className="flex justify-between items-start mb-1">
                                      <h4 className="font-bold text-gray-800 text-sm">{app.applicant_details?.first_name} {app.applicant_details?.last_name}</h4>
                                      <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${
                                          app.application_status === 'Pending' ? 'bg-blue-50 text-blue-600 border-blue-100' : 
                                          app.application_status === 'Hired' ? 'bg-green-50 text-green-600 border-green-100' :
                                          'bg-gray-50 text-gray-600 border-gray-200'
                                      }`}>{app.application_status}</span>
                                  </div>
                                  <p className="text-xs text-gray-500 truncate">{app.job_posting?.job_title}</p>
                                  <p className="text-[10px] text-gray-400 mt-2">{new Date(app.applied_at).toLocaleDateString()}</p>
                              </div>
                          ))}
                          {applications.length === 0 && <div className="p-8 text-center text-gray-400 text-sm">No applicants yet.</div>}
                      </div>

                      {/* Detail View / Chat */}
                      <div className="w-2/3 flex flex-col bg-gray-50/50">
                          {selectedApplicant ? (
                              <>
                                {/* Detail Header */}
                                <div className="p-6 bg-white border-b border-gray-100 flex justify-between items-start">
                                    <div>
                                        <h2 className="text-xl font-bold text-gray-800">{selectedApplicant.applicant_details?.first_name} {selectedApplicant.applicant_details?.last_name}</h2>
                                        <p className="text-sm text-gray-500">{selectedApplicant.applicant_details?.program} • {selectedApplicant.job_posting?.job_title}</p>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => viewResume(selectedApplicant.applicant_details!)} className="px-3 py-2 bg-gray-100 text-gray-600 rounded-lg text-xs font-bold hover:bg-gray-200 flex items-center gap-1">
                                            <FileText size={14} /> Resume
                                        </button>

                                        {selectedApplicant.application_status !== 'Hired' && (
                                            <button onClick={() => updateApplicationStatus(selectedApplicant.id, 'Hired')} className="px-3 py-2 bg-green-600 text-white rounded-lg text-xs font-bold hover:bg-green-700 flex items-center gap-1">
                                                <CheckCircle size={14} /> Hire
                                            </button>
                                        )}
                                        {selectedApplicant.application_status === 'Pending' && (
                                            <button onClick={() => updateApplicationStatus(selectedApplicant.id, 'Rejected')} className="px-3 py-2 bg-red-100 text-red-600 rounded-lg text-xs font-bold hover:bg-red-200 flex items-center gap-1">
                                                <XCircle size={14} /> Reject
                                            </button>
                                        )}
                                    </div>
                                </div>

                                {/* Chat Area */}
                                <div className="flex-grow p-4 overflow-y-auto space-y-3">
                                    {messages.length === 0 && <div className="text-center text-gray-400 text-sm py-10">Start a conversation with the applicant.</div>}
                                    {messages.map(msg => (
                                        <div key={msg.id} className={`flex ${msg.sender_type === 'HR' ? 'justify-end' : 'justify-start'}`}>
                                            <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${msg.sender_type === 'HR' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white border border-gray-200 text-gray-700 rounded-tl-none'}`}>
                                                {msg.message}
                                            </div>
                                        </div>
                                    ))}
                                    <div ref={messagesEndRef} />
                                </div>

                                {/* Input */}
                                <form onSubmit={sendMessage} className="p-4 bg-white border-t border-gray-100 flex gap-2">
                                    <input 
                                        type="text" 
                                        value={newMessage} 
                                        onChange={e => setNewMessage(e.target.value)} 
                                        placeholder="Type a message..."
                                        className="flex-grow bg-gray-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-100 outline-none"
                                    />
                                    <button type="submit" className="p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors">
                                        <Send size={18} />
                                    </button>
                                </form>
                              </>
                          ) : (
                              <div className="flex flex-col items-center justify-center h-full text-gray-400">
                                  <Users size={40} className="mb-2 opacity-50"/>
                                  <p>Select an applicant to view details and chat.</p>
                              </div>
                          )}
                      </div>
                  </div>
              )}
          </div>
      </div>

      {/* JOB FORM MODAL */}
      {showJobForm && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-gray-900/50 backdrop-blur-sm" onClick={() => setShowJobForm(false)}></div>
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg relative z-10 p-8 animate-fade-in">
                  <h3 className="text-2xl font-bold mb-6 text-gray-800">{jobFormData.id ? 'Edit Job' : 'Post New Job'}</h3>
                  <form onSubmit={handleJobSubmit} className="space-y-4">
                      <div>
                          <label className="text-xs font-bold text-gray-500 uppercase">Job Title</label>
                          <input required type="text" value={jobFormData.job_title || ''} onChange={e => setJobFormData({...jobFormData, job_title: e.target.value})} className="w-full p-3 bg-gray-50 rounded-xl border-none text-sm font-semibold focus:ring-2 focus:ring-indigo-200 outline-none" />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                          <div>
                              <label className="text-xs font-bold text-gray-500 uppercase">Type</label>
                              <select value={jobFormData.employment_type} onChange={e => setJobFormData({...jobFormData, employment_type: e.target.value})} className="w-full p-3 bg-gray-50 rounded-xl border-none text-sm font-semibold focus:ring-2 focus:ring-indigo-200 outline-none">
                                  <option value="Full-Time">Full-Time</option>
                                  <option value="Part-Time">Part-Time</option>
                                  <option value="Contract">Contract</option>
                                  <option value="Internship">Internship</option>
                              </select>
                          </div>
                          <div>
                              <label className="text-xs font-bold text-gray-500 uppercase">Location</label>
                              <input type="text" value={jobFormData.location || ''} onChange={e => setJobFormData({...jobFormData, location: e.target.value})} className="w-full p-3 bg-gray-50 rounded-xl border-none text-sm font-semibold focus:ring-2 focus:ring-indigo-200 outline-none" />
                          </div>
                      </div>
                       <div>
                          <label className="text-xs font-bold text-gray-500 uppercase">Salary Range</label>
                          <input type="text" placeholder="e.g. 25k - 30k" value={jobFormData.salary_range || ''} onChange={e => setJobFormData({...jobFormData, salary_range: e.target.value})} className="w-full p-3 bg-gray-50 rounded-xl border-none text-sm font-semibold focus:ring-2 focus:ring-indigo-200 outline-none" />
                      </div>
                      <div>
                          <label className="text-xs font-bold text-gray-500 uppercase">Description</label>
                          <textarea required rows={5} value={jobFormData.job_description || ''} onChange={e => setJobFormData({...jobFormData, job_description: e.target.value})} className="w-full p-3 bg-gray-50 rounded-xl border-none text-sm font-semibold focus:ring-2 focus:ring-indigo-200 outline-none resize-none" />
                      </div>
                      <div className="flex gap-3 pt-2">
                          <button type="button" onClick={() => setShowJobForm(false)} className="flex-1 py-3 bg-gray-100 text-gray-600 font-bold rounded-xl hover:bg-gray-200">Cancel</button>
                          <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg">{jobFormData.id ? 'Update' : 'Post Now'}</button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* RESUME VIEWER MODAL */}
      {resumeUrl && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
               <div className="absolute inset-0 bg-gray-900/80 backdrop-blur-sm" onClick={() => setResumeUrl(null)}></div>
               <div className="bg-white rounded-2xl w-full max-w-4xl h-[85vh] relative z-10 flex flex-col">
                   <div className="p-4 border-b flex justify-between items-center">
                       <h3 className="font-bold text-lg">Applicant Resume</h3>
                       <button onClick={() => setResumeUrl(null)}><X size={24}/></button>
                   </div>
                   <div className="flex-grow bg-gray-100 p-1">
                       <iframe src={resumeUrl} className="w-full h-full rounded-b-xl" title="Resume" />
                   </div>
               </div>
          </div>
      )}

    </div>
  );
};

export default HRDashboard;
